sql:
SELECT COUNT(DISTINCT nation_id) AS num_nations
FROM resources
WHERE resource_extraction_rate > 50;

SELECT nation_id, MIN(gdp) AS min_gdp
FROM economics
GROUP BY nation_id;

SELECT nation_id, military_technology 
FROM military 
WHERE military_technology = 'High';

SELECT gdp_history.nation_id, gdp_history.gdp_value, gdp_history.recorded_year
FROM gdp_history
WHERE gdp_history.gdp_growth_rate > (SELECT AVG(gdp_growth_rate) FROM gdp_history);

SELECT alliance_strength, alliance_benefits, alliance_obligations, alliance_duration, alliance_status, COUNT(*) AS nation_count
FROM alliances
GROUP BY alliance_strength, alliance_benefits, alliance_obligations, alliance_duration, alliance_status;

SELECT nation_id, AVG(gdp_per_capita) AS average_gdp_per_capita
FROM gdp_history
GROUP BY nation_id;

SELECT nation_id, training_programs
FROM training_centers
WHERE training_programs > (SELECT AVG(training_programs) FROM training_centers);

SELECT *
FROM training_centers
WHERE training_efficacy = 'High' AND training_cost < '$5000';

SELECT navy_id
FROM navy
WHERE navy_strength = 'Strong';

SELECT L.leader_name
FROM leadership L
JOIN (
    SELECT nation_id
    FROM economics
    WHERE gdp = (
        SELECT MAX(gdp) 
        FROM economics
    )
) E ON L.nation_id = E.nation_id;

SELECT l.leader_name, l.leader_gender, a.alliance_name, a.alliance_status
FROM leadership l
JOIN alliances a ON l.nation_id = a.nation_id;

SELECT gdp_value, gdp_growth_rate, gdp_per_capita, gdp_sector_distribution 
FROM gdp_history 
WHERE recorded_year = 2023;

SELECT leader_name, leader_age
FROM leadership
WHERE leader_age > (SELECT AVG(leader_age) FROM leadership);

SELECT *
FROM resources
ORDER BY oil_production DESC;

SELECT COUNT(DISTINCT nation_id) 
FROM gdp_history 
WHERE gdp_per_capita > 10000;

external_knowledge:
- 'rich in oil' refers to an oil production capacity greater than '6000 Tons per month';
- 'low unemployment rates' refers to an unemployment rate less than '5%';
- 'manageable foreign debts' refers to foreign debts less than 20% of gdp_value.
